<template>
  <v-container fluid>
    <v-row class="mb-n8 mt-n4">
      <v-col>
        <v-date-picker v-model="dates" :min="minDate" :color="color" :events="events"
                       :event-color="eventColor" first-day-of-week="1" locale="NL-nl" multiple
                       :disabled="color === '#ccc'"></v-date-picker>
      </v-col>
    </v-row>

    <v-row class="mb-n8">
      <v-col>
        <v-select @change="changeSelect(shift.color)" v-model="shift" :items="shifts" label="Dienst" item-text='name'
                  :disabled="isDelete" outlined>
          <template v-slot:selection="{ item, index }">
            <v-avatar :color="item.color" size="30" class="mr-4"></v-avatar>
            {{ item.name }}
          </template>
          <template v-slot:item="{ item, index }">
            <v-avatar :color="item.color" size="30" class="mr-4"></v-avatar>
            {{ item.name }}
          </template>
        </v-select>
      </v-col>
    </v-row>

    <v-row class="mb-n6">
      <v-col>
        <v-btn v-if="!isDelete" :disabled="(dates.length > 0 && color != '#000')" block @click="isDelete = true; dates = []" outlined>verwijderen</v-btn>
        <v-btn v-if="isDelete" block @click="isDelete = false; dates = []" outlined>terug</v-btn>
      </v-col>
      <v-col>
        <v-btn block @click="setDates" :disabled="(dates.length < 1 && color != '#000') || isDelete" outlined>stel in
        </v-btn>
      </v-col>
      <v-col v-if="!isDelete">
        <v-btn @click="saveAll(events)" block :disabled="!hasEvents()" outlined>opslaan</v-btn>
      </v-col>
      <v-col v-else>
        <v-btn @click="deleteAll(events)" block :disabled="dates.length < 1" color="red" outlined>verwijder</v-btn>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import {shifts, dates, datesMap, events, isDelete, getShift, saveAll, deleteAll, hasEvents, ui, calSet} from '../state';
import {ref, watch} from '@vue/composition-api';

// const  = new Map();

const D = new Date();
const YEAR = D.getFullYear();
const MONTH = ((D.getMonth() + 1) + "").padStart(2, "0");
const DAY = (D.getDate() + "").padStart(2, "0");
const minDate = YEAR + "-" + MONTH + "-" + DAY;

export default {
  name: 'Calendar',
  setup(props) {
    const shift = ref('');
    const eventsColors = ref(['red']);
    // watch(isDelete, () => {
    //   console.log("jojojojo");
    // })
    return {shifts, dates, events, isDelete, eventsColors, shift, getShift, saveAll, deleteAll, hasEvents};
  },
  data: () => ({
    minDate
  }),
  created() {
  },
  methods: {
    pushEvents() {
      console.log("dates ", dates);
      console.log("events ", events);
      this.events = Array.from(new Set([...this.events, ...this.dates]));
      console.log(events);
      console.log(datesMap);
      console.log(calSet);
    },
    setDates() {
      for (const SELECT of this.dates) {
        datesMap.set(SELECT, this.color);
      }
      this.pushEvents();
      this.dates = [];
    },
    eventColor(day) {
      return datesMap.get(day);
    },
    changeSelect(color) {
      isDelete.value = false;
      dates.value = [];
      // console.log("changeSelect");
      // console.log(color);
      // this.selected = color;
    },
    pick(date) {
      console.log("date ", date);
      console.log("===========================");
    }
  },
  computed: {
    color() {
      const SHIFT = getShift(this.shift);
      if (isDelete.value) {
        return '#000';
      } else if (SHIFT) {
        return SHIFT.color;
      } else {
        return '#ccc';
      }
    }
  }
}
</script>


