const getEvent = (info) => {
    let dateEnd;
    if (info.start > info.end) {
        const DATE = new Date(info.date);
        DATE.setDate(DATE.getDate() + 1);
        dateEnd = DATE.toISOString().split('T')[0];
    } else {
        dateEnd = info.date;
    }
    const COLOR_ID = getColorId(info.color);
    return {
        'summary': info.name,
        'start': {
            'dateTime': `${info.date}T${info.start}:00`,
            'timeZone': 'Europe/Amsterdam'
        },
        'end': {
            'dateTime': `${dateEnd}T${info.end}:00`,
            'timeZone': 'Europe/Amsterdam'
        },
        "colorId": COLOR_ID,
    }
}

