const deleteEvents = async (events) => {
    console.log("DELETE ", events);
    const BATCH = gapi.client.newBatch();

    for(const EVENT of events) {
        const request = gapi.client.calendar.events.delete({
            'calendarId': 'primary',
            'eventId': EVENT
        });
        BATCH.add(request);
    }

    try {
        await BATCH;
        console.log("yess");
        snackText.value = `diensten zijn verwijderd`;
        clearEvents()
        await listUpcomingEvents();
    } catch (e) {
        console.log(" OOPS ");
    }

}

const createCalendarItems = async (info) => {
    console.log(" ==> create ==> ", info);
    const BATCH = gapi.client.newBatch();
    let count = 0;
    for (const ITEM of info) {
        if (!calSet.has(ITEM.date)) {
            count++;
            BATCH.add(gapi.client.calendar.events.insert({"calendarId": "primary", "resource": getEvent(ITEM)}))
        }
    }
    try {
        if (count > 0) {
            await BATCH;
        }
        console.log(count);
        snackText.value = `${count} diensten toegevoegd`;
        clearEvents()
        await listUpcomingEvents();
    } catch (e) {
        console.log("Error ", e);
    }
}

