      console.log("save ", this.name, this.color, this.startTime, this.endTime);
      this.shifts.push({name: this.name, color: this.color, start: this.startTime, end: this.endTime});
      ui.showAddShift = false;
    }
  },
  computed: {
    disableSave() {
      return !(this.name && this.color && this.startTime && this.endTime);
    }
  }
}
