const loadShifts = () => {
    const selection = JSON.parse(localStorage.getItem('shifts')) || [];
    shifts.value = selection;
}

const saveShifts = () => {
    localStorage.setItem("shifts", JSON.stringify([...shifts.value]));
}

const removeShift = (name) => {
    for (let i = 0; i < shifts.value.length; i++) {
        if (shifts.value[i].name === name) {
            shifts.value.splice(i, 1);
            break;
        }
    }
}

const getShift = (name) => {
    for (const SHIFT of shifts.value) {
        if (SHIFT.name === name) {
            return SHIFT
        }
    }
}

const getShiftByColor = (color) => {
    for (const SHIFT of shifts.value) {
        if (SHIFT.color === color) {
            return SHIFT
        }
    }
}

const saveAll = async () => {
    const shiftsOut = [];
    for (const [SHIFT, COLOR] of datesMap) {
        if (!calSet.has(SHIFT)) {
            shiftsOut.push({date: SHIFT, ...getShiftByColor(COLOR)});
        }
    }
    console.log(shiftsOut);
    await createCalendarItems(shiftsOut);
}

const deleteAll = () => {
    // console.log(dates.value);
    console.log(events.value);
    // console.log(calSet);
    // console.log(calMap);
    console.log("")
    const deleteIds = [];
    for(const DATE of dates.value) {
        if(calMap.has(DATE)) {
            console.log("delete ", calMap.get(DATE));
            deleteIds.push(calMap.get(DATE).id);
        } else if(events.value.includes(DATE)) {
            events.value.splice(events.value.indexOf(DATE), 1);
        }
    }
    console.log(deleteIds);
    if(deleteIds.length > 0) {
        deleteEvents(deleteIds);
    }
    dates.value = [];
    isDelete.value = false;
}

const setEvent = (event, shift) => {
    // console.log("set event ", event);
    const DATE = event.start.dateTime.substring(0, 10);
    // console.log(shift);
    events.value.push(DATE);
    calSet.add(DATE);
    // console.log("set event ", event);
    calMap.set(DATE, event);
    // console.log(DATE);
    datesMap.set(DATE, shift.color);
}

const clearEvents = () => {
    events.value = [];
    datesMap.clear();
    calSet.clear();
}

const hasEvents = () => {
    let count = 0;
    for (const EVENT of events.value) {
        if (!calSet.has(EVENT)) {
            return true;
        }
    }
    return false;
}


