<template>
  <v-container fluid>
    <v-row>
      <v-col class="d-flex">
        <v-spacer></v-spacer>
        <v-btn @click="ui.showEditShift = false" right text icon>
          <v-icon>mdi-close</v-icon>
        </v-btn>
      </v-col>
    </v-row>

    <v-row class="mb-n14">
      <v-col>
        <v-col>
          {{prevName}}
          <v-text-field v-model="name" label="naam" outlined></v-text-field>
        </v-col>
      </v-col>
    </v-row>

    <v-row class="mb-n14">
      <v-col>
        <v-col>
          <v-select v-model="color" :items="colors" label="Kleur" item-text='color' outlined>
            <template v-slot:selection="{ item, index }">
              <v-avatar :color="item.color" size="30" class="mr-4"></v-avatar>
              {{ item.name }}
            </template>
            <template v-slot:item="{ item, index }">
              <v-avatar :color="item.color" size="30" class="mr-4"></v-avatar>
              {{ item.name }}
            </template>
          </v-select>
        </v-col>
      </v-col>
    </v-row>

    <v-row>
      <v-col>
        <v-dialog ref="dialogStart" v-model="dialogStart" :return-value.sync="startTime" persistent width="290px">
          <template v-slot:activator="{ on, attrs }">
            <v-text-field v-model="startTime" label="Picker in dialog" prepend-icon="mdi-clock-time-four-outline" readonly
                          v-bind="attrs" v-on="on"></v-text-field>
          </template>
          <v-time-picker v-if="dialogStart" v-model="startTime" format="24hr" full-width>
            <v-spacer></v-spacer>
            <v-btn text color="primary" @click="dialog = false">
              Cancel
            </v-btn>
            <v-btn text color="primary" @click="$refs.dialogStart.save(startTime)">
              OK
            </v-btn>
          </v-time-picker>
        </v-dialog>
      </v-col>

      <v-col>
        <v-dialog ref="dialogEnd" v-model="dialogEnd" :return-value.sync="endTime" persistent width="290px">
          <template v-slot:activator="{ on, attrs }">
            <v-text-field v-model="endTime" label="Picker in dialog" prepend-icon="mdi-clock-time-four-outline" readonly
                          v-bind="attrs" v-on="on"></v-text-field>
          </template>
          <v-time-picker v-if="dialogEnd" v-model="endTime" format="24hr" full-width>
            <v-spacer></v-spacer>
            <v-btn text color="primary" @click="dialogEnd = false">
              Cancel
            </v-btn>
            <v-btn text color="primary" @click="$refs.dialogEnd.save(endTime)">
              OK
            </v-btn>
          </v-time-picker>
        </v-dialog>
      </v-col>
    </v-row>

    <v-row>
      <v-col>
        <v-btn @click="saveShift" :disabled="disableSave" block outlined>save</v-btn>
      </v-col>
    </v-row>
  </v-container>
</template>


<script>
import {ref, reactive, watch} from '@vue/composition-api'

import {shifts, shift, ui, getShift, removeShift} from '../state'
import {COLORS} from '../state/constant'


export default {
  name: 'Settings',
  setup() {
    const prevName = ref(shift.value);
    // console.log(shift);
    // console.log(getShift(prevName.value))
    return {shifts, shift, ui, colors: COLORS, prevName, getShift, removeShift}
  },
  data: () => ({
    name: 'test',
    color: '',
    start: '',
    startTime: '09:00',
    endTime: '12:00',
    add: false,
    dialogStart: false,
    dialogEnd: false
  }),
  created() {
    const shift = getShift(this.prevName)
    this.name = shift.name;
    this.startTime = shift.start;
    this.endTime = shift.end;
    this.color = shift.color;

  },
  methods: {
    saveShift() {
      console.log("save ", this.name, this.color, this.startTime, this.endTime);
      this.removeShift(this.prevName);
      const SHIFT = {name: this.name, color: this.color, start: this.startTime, end: this.endTime};
      this.shifts.push(SHIFT);
      this.shift = this.name;
      ui.showEditShift = false;
    }
  },
  computed: {
    disableSave() {
      return !(this.name && this.color && this.startTime && this.endTime);
    }
  }
}
</script>
